from __future__ import annotations

from dataclasses import dataclass

from django.conf import settings


@dataclass
class CmdResult:
    ok: bool
    exit_code: int
    stdout: str
    stderr: str


def subprocess_allowed() -> bool:
    return bool(getattr(settings, 'INTERFACEMANAGE_ALLOW_SUBPROCESS', False))


def command_timeout() -> int:
    return int(getattr(settings, 'INTERFACEMANAGE_COMMAND_TIMEOUT', 8))


def run(argv: list[str], *, timeout: int | None = None) -> CmdResult:
    if not subprocess_allowed():
        return CmdResult(ok=False, exit_code=-1, stdout='', stderr='subprocess disabled')

    import subprocess

    t = timeout if timeout is not None else command_timeout()
    try:
        proc = subprocess.run(
            argv,
            capture_output=True,
            text=True,
            timeout=t,
            check=False,
        )
        return CmdResult(
            ok=proc.returncode == 0,
            exit_code=proc.returncode,
            stdout=proc.stdout or '',
            stderr=proc.stderr or '',
        )
    except FileNotFoundError:
        return CmdResult(ok=False, exit_code=-1, stdout='', stderr=f'not found: {argv[0]}')
    except subprocess.TimeoutExpired:
        return CmdResult(ok=False, exit_code=-1, stdout='', stderr='timeout')
    except Exception as exc:  # noqa: BLE001
        return CmdResult(ok=False, exit_code=-1, stdout='', stderr=str(exc))

from __future__ import annotations

import json
from pathlib import Path
from typing import Any

import yaml
from django.conf import settings


def _netplan_dirs() -> list[Path]:
    dirs = getattr(settings, 'INTERFACEMANAGE_NETPLAN_DIRS', ['/etc/netplan'])
    out: list[Path] = []
    for d in dirs:
        p = Path(d)
        if p.is_dir():
            out.append(p)
    return out


def _deep_merge(a: dict[str, Any], b: dict[str, Any]) -> dict[str, Any]:
    for key, val in b.items():
        if key in a and isinstance(a[key], dict) and isinstance(val, dict):
            _deep_merge(a[key], val)
        else:
            a[key] = val
    return a


def load_netplan() -> dict[str, Any]:
    """读取 netplan YAML：按文件列出解析结果，并给出浅层合并后的 network 树。"""
    files: dict[str, Any] = {}
    merged_network: dict[str, Any] = {}
    errors: list[dict[str, str]] = []

    for base in _netplan_dirs():
        for path in sorted(base.glob('*.yaml')) + sorted(base.glob('*.yml')):
            rel = str(path)
            try:
                text = path.read_text(encoding='utf-8')
            except OSError as exc:
                errors.append({'file': rel, 'error': str(exc)})
                continue
            try:
                data = yaml.safe_load(text) or {}
            except yaml.YAMLError as exc:
                errors.append({'file': rel, 'error': f'YAML error: {exc}'})
                continue
            files[rel] = data
            net = data.get('network')
            if isinstance(net, dict):
                _deep_merge(merged_network, net)

    return {
        'netplan_version': merged_network.get('version'),
        'merged_network': merged_network,
        'files': files,
        'errors': errors,
        'summary': {
            'file_count': len(files),
            'sections': sorted(k for k in merged_network.keys() if k != 'version'),
        },
    }


def netplan_as_json(netplan: dict[str, Any]) -> str:
    return json.dumps(netplan, ensure_ascii=False, indent=2, default=str)


def index_netplan_interfaces(merged_network: dict[str, Any]) -> dict[str, dict[str, Any]]:
    """将 netplan 各段落按接口名索引，便于与内核 ifname 对齐。"""
    out: dict[str, dict[str, Any]] = {}
    if not merged_network:
        return out

    section_map = {
        'ethernets': 'ethernet',
        'wifis': 'wifi',
        'bridges': 'bridge',
        'bonds': 'bond',
        'vlans': 'vlan',
        'tunnels': 'tunnel',
        'vrfs': 'vrf',
    }

    for section, kind in section_map.items():
        block = merged_network.get(section)
        if not isinstance(block, dict):
            continue
        for ifname, spec in block.items():
            if not isinstance(spec, dict):
                continue
            entry = {'section': section, 'kind': kind, 'spec': spec}
            if ifname in out:
                entry['note'] = 'duplicate name in netplan;后者覆盖展示'
            out[ifname] = entry
    return out

from __future__ import annotations

import json
import re
from typing import Any

from interfacemanage.services import subprocess_util


def _parse_ip_json(stdout: str) -> list[dict[str, Any]] | dict[str, Any] | None:
    if not stdout.strip():
        return None
    try:
        return json.loads(stdout)
    except json.JSONDecodeError:
        return None


def ip_link_show() -> dict[str, Any]:
    res = subprocess_util.run(['ip', '-json', 'link', 'show'])
    data = _parse_ip_json(res.stdout) if res.ok else None
    return {
        'ok': res.ok,
        'exit_code': res.exit_code,
        'stderr': res.stderr,
        'links': data if isinstance(data, list) else [],
    }


def ip_addr_show() -> dict[str, Any]:
    res = subprocess_util.run(['ip', '-json', 'addr', 'show'])
    data = _parse_ip_json(res.stdout) if res.ok else None
    return {
        'ok': res.ok,
        'exit_code': res.exit_code,
        'stderr': res.stderr,
        'addresses': data if isinstance(data, list) else [],
    }


def ip_route_show() -> dict[str, Any]:
    res = subprocess_util.run(['ip', '-json', 'route', 'show'])
    data = _parse_ip_json(res.stdout) if res.ok else None
    return {
        'ok': res.ok,
        'exit_code': res.exit_code,
        'stderr': res.stderr,
        'routes': data if isinstance(data, list) else [],
    }


def ip_tunnel_show_text() -> dict[str, Any]:
    """`ip tunnel show` 文本输出（GRE/IPIP/SIT 等），兼容无 JSON 子命令的环境。"""
    res = subprocess_util.run(['ip', 'tunnel', 'show'])
    return {
        'ok': res.ok,
        'exit_code': res.exit_code,
        'stderr': res.stderr,
        'raw': res.stdout,
    }


_TUNNEL_LINE = re.compile(
    r'^(?P<name>[^:]+):\s*(?P<mode>[^\s/]+)/(?:ipv6\s+)?(?P<rest>.*)$'
)


def parse_tunnel_show(raw: str) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for line in raw.splitlines():
        line = line.strip()
        if not line:
            continue
        m = _TUNNEL_LINE.match(line)
        if not m:
            rows.append({'raw': line})
            continue
        rows.append(
            {
                'ifname': m.group('name').strip(),
                'mode': m.group('mode').strip(),
                'details': m.group('rest').strip(),
            }
        )
    return rows


def ip_link_show_filtered(link_type: str) -> dict[str, Any]:
    """例如 type vxlan / gre / gretap ..."""
    res = subprocess_util.run(['ip', '-json', 'link', 'show', 'type', link_type])
    data = _parse_ip_json(res.stdout) if res.ok else None
    return {
        'type': link_type,
        'ok': res.ok,
        'exit_code': res.exit_code,
        'stderr': res.stderr,
        'links': data if isinstance(data, list) else [],
    }


def collect_kernel_snapshot() -> dict[str, Any]:
    link = ip_link_show()
    addr = ip_addr_show()
    route = ip_route_show()
    tunnel_raw = ip_tunnel_show_text()
    tunnels_parsed = parse_tunnel_show(tunnel_raw['raw']) if tunnel_raw.get('ok') else []

    typed: dict[str, Any] = {}
    for t in ('vxlan', 'gre', 'gretap', 'ip6gre', 'geneve', 'bridge', 'bond', 'vlan'):
        typed[t] = ip_link_show_filtered(t)

    addrs_by_if: dict[str, list[dict[str, Any]]] = {}
    for item in addr.get('addresses') or []:
        if not isinstance(item, dict):
            continue
        name = item.get('ifname')
        if not name:
            continue
        addrs_by_if.setdefault(str(name), []).append(item)

    return {
        'link': link,
        'address': addr,
        'route': route,
        'tunnel_show': {**tunnel_raw, 'parsed': tunnels_parsed},
        'typed_links': typed,
        'addresses_by_ifname': addrs_by_if,
    }

from __future__ import annotations

from typing import Any

from interfacemanage.services import subprocess_util


def wg_show_interfaces() -> dict[str, Any]:
    res = subprocess_util.run(['wg', 'show', 'interfaces'])
    if not res.ok:
        return {'ok': False, 'exit_code': res.exit_code, 'stderr': res.stderr, 'interfaces': []}
    names = [x.strip() for x in res.stdout.splitlines() if x.strip()]
    return {'ok': True, 'exit_code': res.exit_code, 'stderr': res.stderr, 'interfaces': names}


def wg_show_dump(ifname: str) -> dict[str, Any]:
    res = subprocess_util.run(['wg', 'show', ifname, 'dump'])
    if not res.ok:
        return {'ok': False, 'ifname': ifname, 'stderr': res.stderr, 'device': None, 'peers': []}
    return {'ok': True, 'ifname': ifname, **parse_wg_dump(res.stdout)}


def parse_wg_dump(raw: str) -> dict[str, Any]:
    lines = [ln for ln in raw.splitlines() if ln.strip()]
    if not lines:
        return {'device': None, 'peers': []}

    dev_fields = lines[0].split('\t')
    device = {
        'private_key': dev_fields[0] if len(dev_fields) > 0 else None,
        'public_key': dev_fields[1] if len(dev_fields) > 1 else None,
        'listen_port': dev_fields[2] if len(dev_fields) > 2 else None,
        'fwmark': dev_fields[3] if len(dev_fields) > 3 else None,
    }

    peers: list[dict[str, Any]] = []
    for ln in lines[1:]:
        f = ln.split('\t')
        if len(f) < 8:
            peers.append({'raw': ln})
            continue
        peers.append(
            {
                'public_key': f[0],
                'preshared_key': f[1],
                'endpoint': f[2],
                'allowed_ips': f[3],
                'latest_handshake': f[4],
                'transfer_rx': f[5],
                'transfer_tx': f[6],
                'persistent_keepalive': f[7],
            }
        )

    return {'device': device, 'peers': peers}


def collect_wireguard_overview() -> dict[str, Any]:
    iface_res = wg_show_interfaces()
    if not iface_res['ok']:
        return {'ok': False, 'stderr': iface_res.get('stderr'), 'interfaces': {}}

    out: dict[str, Any] = {}
    for name in iface_res.get('interfaces') or []:
        out[name] = wg_show_dump(name)
    return {'ok': True, 'interfaces': out}

from __future__ import annotations

from typing import Any

from interfacemanage.services.netplan import index_netplan_interfaces


def _flags_up(flags: Any) -> bool | None:
    if not isinstance(flags, list):
        return None
    return 'UP' in flags


def _classify_kind(link: dict[str, Any]) -> str:
    linkinfo = link.get('linkinfo') or {}
    if isinstance(linkinfo, dict):
        kind = linkinfo.get('info_kind')
        if kind:
            return str(kind)
    lt = link.get('link_type')
    if lt:
        return str(lt)
    if link.get('link_netnsid') is not None:
        return 'netns'
    return 'ethernet'


def _tunnel_mode_from_netplan(spec: dict[str, Any]) -> str | None:
    mode = spec.get('mode')
    if isinstance(mode, str):
        return mode
    return None


def unify_interfaces(
    *,
    netplan_bundle: dict[str, Any],
    kernel: dict[str, Any],
    wireguard: dict[str, Any],
) -> list[dict[str, Any]]:
    merged = netplan_bundle.get('merged_network') or {}
    np_idx = index_netplan_interfaces(merged if isinstance(merged, dict) else {})

    links = (kernel.get('link') or {}).get('links') or []
    if not isinstance(links, list):
        links = []

    addrs_by_if = kernel.get('addresses_by_ifname') or {}

    wg_ifaces = {}
    if wireguard.get('ok') and isinstance(wireguard.get('interfaces'), dict):
        wg_ifaces = wireguard['interfaces']

    tunnel_parsed = ((kernel.get('tunnel_show') or {}).get('parsed')) or []
    tunnel_by_name = {
        str(row['ifname']): row for row in tunnel_parsed if isinstance(row, dict) and row.get('ifname')
    }

    rows: list[dict[str, Any]] = []
    for link in links:
        if not isinstance(link, dict):
            continue
        name = link.get('ifname')
        if not name:
            continue
        name = str(name)
        kind = _classify_kind(link)
        np = np_idx.get(name)

        np_kind = None
        tunnel_mode_np = None
        if np:
            np_kind = np.get('kind')
            tunnel_mode_np = _tunnel_mode_from_netplan(np.get('spec') or {})

        addr_entries = addrs_by_if.get(name) or []

        wg_detail = wg_ifaces.get(name) if kind == 'wireguard' else None

        tunnel_line = tunnel_by_name.get(name)

        rows.append(
            {
                'ifname': name,
                'ifindex': link.get('ifindex'),
                'kind': kind,
                'kind_source': 'kernel',
                'admin_up': _flags_up(link.get('flags')),
                'operstate': link.get('operstate'),
                'mtu': link.get('mtu'),
                'mac': link.get('address'),
                'qdisc': link.get('qdisc'),
                'group': link.get('group'),
                'link_type': link.get('link_type'),
                'linkinfo': link.get('linkinfo'),
                'addresses': addr_entries,
                'netplan': np,
                'netplan_kind': np_kind,
                'netplan_tunnel_mode': tunnel_mode_np,
                'wireguard': wg_detail if isinstance(wg_detail, dict) else None,
                'ip_tunnel_show': tunnel_line,
            }
        )

    rows.sort(key=lambda r: (r.get('ifindex') is None, r.get('ifindex') or 0, r['ifname']))
    return rows


def summarize_by_kind(rows: list[dict[str, Any]]) -> dict[str, int]:
    stats: dict[str, int] = {}
    for r in rows:
        k = str(r.get('kind') or 'unknown')
        stats[k] = stats.get(k, 0) + 1
    return dict(sorted(stats.items(), key=lambda x: x[0]))

