"""
使用 pyroute2（内核 netlink）将 DesiredTunnelConfig 中的 WireGuard 意图应用到本机。

不负责 GRE/VXLAN；持久化 netplan 片段由 netplan_writing 按 netplan 规范单独生成。
"""
from __future__ import annotations

import ipaddress
from typing import Any

from django.conf import settings

from interfacemanage.models import DesiredTunnelConfig
from interfacemanage.services import wireguard as wg_svc


def pyroute2_available() -> bool:
    try:
        import pyroute2  # noqa: F401

        return True
    except ImportError:
        return False


def parse_endpoint(endpoint: str | None) -> tuple[str | None, int | None]:
    """host:port、IPv6 的 [addr]:port → (addr, port)。"""
    if not endpoint or not str(endpoint).strip():
        return None, None
    s = str(endpoint).strip()
    if s.startswith('['):
        end = s.find(']', 1)
        if end != -1 and len(s) > end + 1 and s[end + 1] == ':':
            port_s = s[end + 2 :]
            if port_s.isdigit():
                return s[1:end], int(port_s)
        return None, None
    if ':' in s:
        host, _, port_s = s.rpartition(':')
        if host and port_s.isdigit():
            return host, int(port_s)
    return None, None


def tunnel_dict_to_netplan_wireguard(t: dict[str, Any]) -> dict[str, Any]:
    """
    将前端/数据库存储的 netplan_tunnel 结构转为 netplan 文档中的字段名。
    """
    out: dict[str, Any] = {'mode': 'wireguard'}
    addr = t.get('addresses')
    if isinstance(addr, str) and addr.strip():
        out['addresses'] = [addr.strip()]
    elif isinstance(addr, list):
        out['addresses'] = [str(a).strip() for a in addr if str(a).strip()]
    keys = t.get('keys') or {}
    priv = keys.get('private') if isinstance(keys, dict) else None
    if priv:
        out['keys'] = {'private': str(priv).strip()}
    port = t.get('port')
    if port is None:
        port = t.get('listen_port')
    if port is not None and port != '':
        try:
            out['port'] = int(port)
        except (TypeError, ValueError):
            pass
    if t.get('mark') is not None and t.get('mark') != '':
        try:
            out['mark'] = int(t['mark'])
        except (TypeError, ValueError):
            pass

    peers_in = t.get('peers') or []
    peers_out: list[dict[str, Any]] = []
    for p in peers_in:
        if not isinstance(p, dict):
            continue
        pub = p.get('public_key') or (p.get('keys') or {}).get('public')
        if not pub:
            continue
        peer_yaml: dict[str, Any] = {'keys': {'public': str(pub).strip()}}
        psk = p.get('preshared_key') or (p.get('keys') or {}).get('shared')
        if psk:
            peer_yaml['keys']['shared'] = str(psk).strip()
        ep = p.get('endpoint')
        if ep:
            peer_yaml['endpoint'] = str(ep).strip()
        allowed = p.get('allowed_ips')
        if isinstance(allowed, str) and allowed.strip():
            peer_yaml['allowed-ips'] = [x.strip() for x in allowed.replace(',', ' ').split() if x.strip()]
        elif isinstance(allowed, list) and allowed:
            peer_yaml['allowed-ips'] = [str(x).strip() for x in allowed if str(x).strip()]
        ka = p.get('persistent_keepalive')
        if ka is None:
            ka = p.get('keepalive')
        if ka is not None and ka != '':
            try:
                peer_yaml['keepalive'] = int(ka)
            except (TypeError, ValueError):
                pass
        peers_out.append(peer_yaml)
    if peers_out:
        out['peers'] = peers_out
    return out


def build_wireguard_tunnels_netplan() -> dict[str, Any]:
    """供写入 99-pemanager-wireguard.yaml 的 tunnels 字典（字段符合 netplan）。"""
    tunnels: dict[str, Any] = {}
    for obj in DesiredTunnelConfig.objects.all().order_by('ifname'):
        if obj.kind != DesiredTunnelConfig.TunnelKind.WIREGUARD:
            continue
        name = (obj.ifname or '').strip()
        if not name:
            continue
        spec = obj.spec or {}
        raw = spec.get('netplan_tunnel') or {}
        if not raw:
            continue
        tunnels[name] = tunnel_dict_to_netplan_wireguard(raw)
    return tunnels


def render_wireguard_netplan_yaml() -> str:
    import yaml

    frag = {'network': {'version': 2, 'tunnels': build_wireguard_tunnels_netplan()}}
    return yaml.safe_dump(
        frag,
        allow_unicode=True,
        default_flow_style=False,
        sort_keys=False,
    )


def _tunnel_from_obj(obj: DesiredTunnelConfig) -> dict[str, Any]:
    spec = obj.spec or {}
    return spec.get('netplan_tunnel') or {}


def _peer_dict_for_pyroute(p: dict[str, Any]) -> dict[str, Any]:
    pub = p.get('public_key') or (p.get('keys') or {}).get('public')
    if not pub:
        raise ValueError('peer 缺少 public_key')
    peer: dict[str, Any] = {'public_key': str(pub).strip()}
    psk = p.get('preshared_key') or (p.get('keys') or {}).get('shared')
    if psk:
        peer['preshared_key'] = str(psk).strip()
    ep_addr, ep_port = parse_endpoint(p.get('endpoint'))
    if ep_addr and ep_port:
        peer['endpoint_addr'] = ep_addr
        peer['endpoint_port'] = ep_port
    allowed = p.get('allowed_ips')
    ips: list[str] = []
    if isinstance(allowed, str) and allowed.strip():
        ips = [x.strip() for x in allowed.replace(',', ' ').split() if x.strip()]
    elif isinstance(allowed, list):
        ips = [str(x).strip() for x in allowed if str(x).strip()]
    if ips:
        peer['allowed_ips'] = ips
        peer['replace_allowed_ips'] = True
    ka = p.get('persistent_keepalive')
    if ka is None:
        ka = p.get('keepalive')
    if ka is not None and ka != '':
        peer['persistent_keepalive'] = int(ka)
    return peer


def _current_peer_pubkeys(ifname: str) -> set[str]:
    d = wg_svc.wg_show_dump(ifname)
    if not d.get('ok'):
        return set()
    out: set[str] = set()
    for p in d.get('peers') or []:
        if isinstance(p, dict) and p.get('public_key'):
            out.add(str(p['public_key']).strip())
    return out


def apply_one_wireguard(obj: DesiredTunnelConfig) -> dict[str, Any]:
    """对单条 WireGuard 意图执行：建接口、写参数、同步对端、地址、up。"""
    if not getattr(settings, 'INTERFACEMANAGE_WG_PYROUTE2_ENABLED', True):
        return {'ifname': obj.ifname, 'ok': False, 'error': 'INTERFACEMANAGE_WG_PYROUTE2_ENABLED 为 False'}

    if not pyroute2_available():
        return {
            'ifname': obj.ifname,
            'ok': False,
            'error': '未安装 pyroute2，请在环境中安装：pip install pyroute2',
        }

    from pyroute2 import IPRoute, NDB, WireGuard

    ifname = (obj.ifname or '').strip()
    t = _tunnel_from_obj(obj)
    keys = t.get('keys') or {}
    priv = keys.get('private') if isinstance(keys, dict) else None
    if not priv or not str(priv).strip():
        return {'ifname': ifname, 'ok': False, 'error': '缺少 keys.private'}
    priv = str(priv).strip()

    port = t.get('port')
    if port is None:
        port = t.get('listen_port')
    try:
        listen_port = int(port) if port is not None and port != '' else None
    except (TypeError, ValueError):
        listen_port = None
    if not listen_port:
        return {'ifname': ifname, 'ok': False, 'error': '缺少有效 listen_port/port'}

    addr_list: list[str] = []
    raw_addr = t.get('addresses')
    if isinstance(raw_addr, str) and raw_addr.strip():
        addr_list = [raw_addr.strip()]
    elif isinstance(raw_addr, list):
        addr_list = [str(a).strip() for a in raw_addr if str(a).strip()]
    if not addr_list:
        return {'ifname': ifname, 'ok': False, 'error': '缺少 addresses（本端 CIDR）'}

    peers_in = [p for p in (t.get('peers') or []) if isinstance(p, dict)]
    desired_peers: list[dict[str, Any]] = []
    desired_pub: set[str] = set()
    for p in peers_in:
        try:
            pd = _peer_dict_for_pyroute(p)
            desired_peers.append(pd)
            desired_pub.add(pd['public_key'])
        except ValueError as exc:
            return {'ifname': ifname, 'ok': False, 'error': str(exc)}

    if not desired_peers:
        return {'ifname': ifname, 'ok': False, 'error': '未配置任何 peer'}

    try:
        with NDB(log='none') as ndb:
            if ifname not in ndb.interfaces:
                ndb.interfaces.create(ifname=ifname, kind='wireguard').commit()
            with ndb.interfaces[ifname] as iface:
                iface.set(state='down')

        with WireGuard() as wg_api:
            fwmark = t.get('fwmark') or t.get('mark')
            kwargs: dict[str, Any] = {'private_key': priv, 'listen_port': listen_port}
            if fwmark is not None and str(fwmark).strip() != '':
                try:
                    kwargs['fwmark'] = int(fwmark)
                except (TypeError, ValueError):
                    pass
            wg_api.set(ifname, **kwargs)

            for pk in _current_peer_pubkeys(ifname):
                if pk not in desired_pub:
                    wg_api.set(ifname, peer={'public_key': pk, 'remove': True})

            for pd in desired_peers:
                wg_api.set(ifname, peer=pd)

        with IPRoute() as ip:
            idxs = ip.link_lookup(ifname=ifname)
            if not idxs:
                return {'ifname': ifname, 'ok': False, 'error': '创建后未找到接口索引'}
            idx = idxs[0]
            ip.flush_addr(index=idx)
            for cidr in addr_list:
                iface = ipaddress.ip_interface(cidr)
                ip.addr(
                    'add',
                    index=idx,
                    address=str(iface.ip),
                    prefixlen=int(iface.network.prefixlen),
                )
            ip.link('set', index=idx, state='up')

        return {'ifname': ifname, 'ok': True}
    except Exception as exc:  # noqa: BLE001
        return {'ifname': ifname, 'ok': False, 'error': str(exc)}


def apply_all_desired_wireguard(
    tunnels: list[DesiredTunnelConfig],
) -> dict[str, Any]:
    """对列表中 kind=wireguard 的条目依次 apply_one_wireguard。"""
    steps: list[dict[str, Any]] = []
    wg_objs = [o for o in tunnels if o.kind == DesiredTunnelConfig.TunnelKind.WIREGUARD]
    if not wg_objs:
        return {'ok': True, 'steps': steps, 'message': '无 WireGuard 意图'}

    all_ok = True
    for obj in wg_objs:
        r = apply_one_wireguard(obj)
        steps.append(r)
        if not r.get('ok'):
            all_ok = False
    return {'ok': all_ok, 'steps': steps}

"""
将 DesiredTunnelConfig 写入 netplan 片段并调用 netplan 校验与 try/apply。
GRE/VXLAN 由 netplan try 生效；WireGuard 由 pyroute2 写入内核，并另写符合 netplan 语法的持久化片段。
"""
from __future__ import annotations

import copy
import os
import subprocess
from typing import Any

import yaml
from django.conf import settings

from interfacemanage.models import DesiredTunnelConfig
from interfacemanage.services import wireguard_apply


class _CmdResult:
    __slots__ = ('ok', 'returncode', 'stdout', 'stderr')

    def __init__(self, ok: bool, returncode: int, stdout: str, stderr: str):
        self.ok = ok
        self.returncode = returncode
        self.stdout = stdout
        self.stderr = stderr


def _cmd_prefix() -> list[str]:
    prefix = getattr(settings, 'INTERFACEMANAGE_NETPLAN_CMD_PREFIX', None) or []
    return [str(x) for x in prefix]


def _timeout(kind: str) -> int:
    if kind == 'apply':
        return int(getattr(settings, 'INTERFACEMANAGE_NETPLAN_APPLY_TIMEOUT', 180))
    return int(getattr(settings, 'INTERFACEMANAGE_COMMAND_TIMEOUT', 30))


def _run(argv: list[str], *, input_text: str | None = None, timeout_kind: str = 'apply') -> _CmdResult:
    if not getattr(settings, 'INTERFACEMANAGE_ALLOW_SUBPROCESS', False):
        return _CmdResult(False, -1, '', 'subprocess disabled (INTERFACEMANAGE_ALLOW_SUBPROCESS)')

    cmd = _cmd_prefix() + argv
    t = _timeout(timeout_kind)
    try:
        proc = subprocess.run(
            cmd,
            input=input_text,
            capture_output=True,
            text=True,
            timeout=t,
            check=False,
        )
        return _CmdResult(
            proc.returncode == 0,
            proc.returncode,
            proc.stdout or '',
            proc.stderr or '',
        )
    except subprocess.TimeoutExpired:
        return _CmdResult(False, -1, '', f'timeout ({t}s): {" ".join(cmd)}')
    except FileNotFoundError:
        return _CmdResult(False, -1, '', f'command not found: {cmd[0] if cmd else argv[0]}')
    except Exception as exc:  # noqa: BLE001
        return _CmdResult(False, -1, '', str(exc))


def build_netplan_tunnels_gre_vxlan() -> dict[str, Any]:
    """仅 GRE / VXLAN，供主 netplan 片段（避免把前端结构化的 WG 字段原样写入导致 netplan 不兼容）。"""
    tunnels: dict[str, Any] = {}
    for obj in DesiredTunnelConfig.objects.all().order_by('ifname'):
        if obj.kind == DesiredTunnelConfig.Kind.WIREGUARD:
            continue
        name = (obj.ifname or '').strip()
        if not name:
            continue
        spec = obj.spec or {}
        t = copy.deepcopy(spec.get('netplan_tunnel') or {})
        if not t:
            continue
        t.setdefault('mode', obj.kind)
        addr = t.get('addresses')
        if isinstance(addr, str) and addr.strip():
            t['addresses'] = [addr.strip()]
        elif isinstance(addr, list):
            t['addresses'] = [str(a).strip() for a in addr if str(a).strip()]
            if not t['addresses']:
                t.pop('addresses', None)
        tunnels[name] = t
    return {'version': 2, 'tunnels': tunnels}


def render_gre_vxlan_fragment_yaml() -> str:
    frag = {'network': build_netplan_tunnels_gre_vxlan()}
    return yaml.safe_dump(
        frag,
        allow_unicode=True,
        default_flow_style=False,
        sort_keys=False,
    )


def _write_netplan_file(path: str, header: str, body: str) -> dict[str, Any]:
    os.makedirs(os.path.dirname(path) or '.', mode=0o755, exist_ok=True)
    fd = os.open(path, os.O_WRONLY | os.O_CREAT | os.O_TRUNC, 0o600)
    with os.fdopen(fd, 'w', encoding='utf-8') as fh:
        fh.write(header)
        fh.write(body)
        if not body.endswith('\n'):
            fh.write('\n')
    return {'path': path, 'ok': True}


def render_empty_wireguard_stub_yaml() -> str:
    return yaml.safe_dump(
        {'network': {'version': 2, 'tunnels': {}}},
        allow_unicode=True,
        default_flow_style=False,
        sort_keys=False,
    )


def apply_desired_tunnels_netplan() -> dict[str, Any]:
    """
    1) 写入 WG 占位片段（tunnels: {}），再写 GRE/VXLAN 主片段，使 netplan try 阶段不套用旧/错误的 WG YAML。
    2) netplan generate + netplan try
    3) pyroute2：将库中 WireGuard 意图应用到内核
    4) 写入符合 netplan 规范的 WG 持久化片段（含 keys/peers 等），供下次开机合并。
    5) 再执行 netplan generate 校验合并结果。
    """
    if not getattr(settings, 'INTERFACEMANAGE_NETPLAN_WRITE_ENABLED', False):
        return {
            'ok': False,
            'error': '写入 netplan 已关闭（settings.INTERFACEMANAGE_NETPLAN_WRITE_ENABLED）',
            'steps': [],
        }

    qs = list(DesiredTunnelConfig.objects.all().order_by('ifname'))
    for obj in qs:
        spec = obj.spec or {}
        t = spec.get('netplan_tunnel') or {}
        addrs = t.get('addresses')
        ok_addr = False
        if isinstance(addrs, str) and addrs.strip():
            ok_addr = True
        elif isinstance(addrs, list) and any(str(a).strip() for a in addrs):
            ok_addr = True
        if not ok_addr:
            return {
                'ok': False,
                'error': f'隧道 {obj.ifname} 缺少本端地址/掩码（addresses，CIDR 如 10.0.0.1/24）',
                'steps': [],
            }

    path = str(
        getattr(settings, 'INTERFACEMANAGE_NETPLAN_FRAGMENT_FILE', '/etc/netplan/99-pemanager-tunnels.yaml')
    )
    wg_path = str(
        getattr(
            settings,
            'INTERFACEMANAGE_NETPLAN_WG_FRAGMENT_FILE',
            '/etc/netplan/99-pemanager-wireguard.yaml',
        )
    )
    steps: list[dict[str, Any]] = []

    try:
        body_gv = render_gre_vxlan_fragment_yaml()
    except Exception as exc:  # noqa: BLE001
        return {'ok': False, 'error': f'生成 GRE/VXLAN YAML 失败: {exc}', 'steps': steps}

    stub = render_empty_wireguard_stub_yaml()

    for label, fpath, content in (
        ('write wireguard stub (pre-try)', wg_path, stub),
        ('write gre/vxlan fragment', path, body_gv),
    ):
        try:
            _write_netplan_file(
                fpath,
                '# Generated by PE Manager — desired tunnel interfaces\n'
                if 'stub' not in label
                else '# Generated by PE Manager — wireguard placeholder before try\n',
                content,
            )
            steps.append({'step': label, 'path': fpath, 'ok': True})
        except OSError as exc:
            steps.append({'step': label, 'path': fpath, 'ok': False, 'stderr': str(exc)})
            return {'ok': False, 'error': f'写入 {fpath} 失败: {exc}', 'steps': steps, 'yaml_preview': content}

    gen = _run(['netplan', 'generate'], timeout_kind='apply')
    steps.append(
        {
            'step': 'netplan generate',
            'ok': gen.ok,
            'returncode': gen.returncode,
            'stderr': gen.stderr,
            'stdout': gen.stdout,
        }
    )
    if not gen.ok:
        return {
            'ok': False,
            'error': 'netplan generate 失败',
            'steps': steps,
            'yaml_preview': body_gv,
        }

    try_timeout = int(getattr(settings, 'INTERFACEMANAGE_NETPLAN_TRY_TIMEOUT', 120))
    try_timeout = max(10, min(try_timeout, 600))

    try_res = _run(
        ['netplan', 'try', '--timeout', str(try_timeout)],
        input_text='\n',
        timeout_kind='apply',
    )
    steps.append(
        {
            'step': 'netplan try',
            'ok': try_res.ok,
            'returncode': try_res.returncode,
            'stderr': try_res.stderr,
            'stdout': try_res.stdout,
            'timeout_sec': try_timeout,
        }
    )
    if not try_res.ok:
        return {
            'ok': False,
            'error': 'netplan try 失败或超时；配置未确认为长期生效，已尝试回滚（以 netplan 行为为准）',
            'steps': steps,
            'yaml_preview': body_gv,
        }

    wg_live = wireguard_apply.apply_all_desired_wireguard(qs)
    steps.append({'step': 'pyroute2 wireguard apply', **wg_live})
    if not wg_live.get('ok'):
        return {
            'ok': False,
            'error': 'pyroute2 应用 WireGuard 失败（详见 steps 中 pyroute2 wireguard apply）',
            'steps': steps,
            'yaml_preview': body_gv,
        }

    try:
        body_wg = wireguard_apply.render_wireguard_netplan_yaml()
    except Exception as exc:  # noqa: BLE001
        return {'ok': False, 'error': f'生成 WireGuard 持久化 YAML 失败: {exc}', 'steps': steps}

    try:
        _write_netplan_file(
            wg_path,
            '# Generated by PE Manager — wireguard persistence (netplan schema)\n',
            body_wg,
        )
        steps.append({'step': 'write wireguard persist fragment', 'path': wg_path, 'ok': True})
    except OSError as exc:
        steps.append({'step': 'write wireguard persist fragment', 'path': wg_path, 'ok': False, 'stderr': str(exc), 'error': str(exc)})
        return {
            'ok': False,
            'error': f'WireGuard 已应用但写入持久化文件失败: {exc}',
            'steps': steps,
        }

    gen2 = _run(['netplan', 'generate'], timeout_kind='apply')
    steps.append(
        {
            'step': 'netplan generate (post-wg-file)',
            'ok': gen2.ok,
            'returncode': gen2.returncode,
            'stderr': gen2.stderr,
            'stdout': gen2.stdout,
        }
    )
    if not gen2.ok:
        return {
            'ok': False,
            'error': '写入 WireGuard netplan 片段后 netplan generate 失败；请检查 YAML 与系统其它 netplan 是否冲突',
            'steps': steps,
        }

    return {
        'ok': True,
        'steps': steps,
        'yaml_preview': body_gv,
        'wireguard_yaml_preview': body_wg,
    }

